/**
 * Webhook notification adapter.
 *
 * Implements NotificationAdapter for the 'webhook' channel with:
 * - URL validation: checks that the webhook URL is a valid HTTP(S) URL
 * - JSON payload formatting: converts NotificationPayload to a JSON POST body
 * - Configurable transport: accepts a WebhookTransport for actual delivery
 *   (defaults to an in-memory transport for development/testing)
 */

import type { NotificationAdapter, SendResult } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Record of a webhook delivery that was sent (or attempted).
 */
export interface SentWebhook {
  url: string;
  payload: WebhookBody;
  sentAt: Date;
}

/**
 * The JSON body POSTed to the webhook URL.
 */
export interface WebhookBody {
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  priority: string;
  metadata?: Record<string, string>;
  timestamp: string;
}

/**
 * Configuration for the WebhookAdapter.
 */
export interface WebhookAdapterConfig {
  /** The webhook endpoint URL to POST to. */
  url: string;
}

/**
 * Transport interface — abstracts how webhook payloads are actually delivered.
 * Implement this for HTTP clients (fetch, axios, etc.).
 */
export interface WebhookTransport {
  post(url: string, body: WebhookBody): Promise<{ success: boolean; errorMessage?: string }>;
}

/**
 * Default in-memory transport: stores webhook deliveries in an array.
 * Suitable for development and testing.
 */
export class InMemoryWebhookTransport implements WebhookTransport {
  private sent: SentWebhook[] = [];

  async post(url: string, body: WebhookBody): Promise<{ success: boolean; errorMessage?: string }> {
    this.sent.push({ url, payload: body, sentAt: new Date() });
    return { success: true };
  }

  getSentWebhooks(): SentWebhook[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
  }
}

const URL_REGEX = /^https?:\/\/[^\s/$.?#].[^\s]*$/;

/**
 * Validates that a URL looks like a valid HTTP(S) URL.
 */
export function isValidWebhookUrl(url: string): boolean {
  return URL_REGEX.test(url);
}

/**
 * Formats a NotificationPayload into the JSON body sent to the webhook.
 */
export function formatWebhookBody(payload: NotificationPayload): WebhookBody {
  return {
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    channel: payload.channel,
    priority: payload.priority,
    metadata: payload.metadata,
    timestamp: new Date().toISOString(),
  };
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'webhook';
  private logger = new Logger('WebhookAdapter');
  private transport: WebhookTransport;
  private config: WebhookAdapterConfig;

  constructor(
    config: WebhookAdapterConfig,
    transport?: WebhookTransport,
  ) {
    this.config = config;
    this.transport = transport ?? new InMemoryWebhookTransport();
  }

  /**
   * Send a webhook notification.
   *
   * 1. Validates the configured webhook URL
   * 2. Formats the notification payload as JSON
   * 3. POSTs it via the configured transport
   *
   * Never throws — returns SendResult with success: false on failure.
   */
  async send(payload: NotificationPayload): Promise<SendResult> {
    try {
      if (!this.config.url || !isValidWebhookUrl(this.config.url)) {
        this.logger.warn(`Invalid webhook URL: ${this.config.url}`);
        return { success: false, errorMessage: `Invalid webhook URL: ${this.config.url}` };
      }

      const body = formatWebhookBody(payload);

      this.logger.info(`Sending webhook to ${this.config.url}: ${payload.subject}`);

      const result = await this.transport.post(this.config.url, body);
      if (!result.success) {
        this.logger.error(`Webhook delivery failed for ${this.config.url}: ${result.errorMessage ?? 'unknown'}`);
        return { success: false, errorMessage: result.errorMessage };
      }

      return { success: true };
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger.error(`Unexpected error sending webhook: ${message}`);
      return { success: false, errorMessage: message };
    }
  }

  /**
   * Get sent webhooks (only works with InMemoryWebhookTransport).
   */
  getSentWebhooks(): SentWebhook[] {
    if (this.transport instanceof InMemoryWebhookTransport) {
      return this.transport.getSentWebhooks();
    }
    return [];
  }

  /**
   * Clear sent webhooks (only works with InMemoryWebhookTransport).
   */
  clearSentWebhooks(): void {
    if (this.transport instanceof InMemoryWebhookTransport) {
      this.transport.clear();
    }
  }
}

