import { describe, it, expect, beforeEach } from 'vitest';
import {
  WebhookAdapter,
  InMemoryWebhookTransport,
  isValidWebhookUrl,
  formatWebhookBody,
} from '../../src/adapters/webhook.adapter.js';
import type { WebhookTransport, WebhookBody } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: 'user-123',
    subject: 'Test Subject',
    body: 'Test body content.',
    channel: 'webhook',
    priority: 'normal',
    ...overrides,
  };
}

describe('WebhookAdapter', () => {
  let transport: InMemoryWebhookTransport;
  let adapter: WebhookAdapter;

  beforeEach(() => {
    transport = new InMemoryWebhookTransport();
    adapter = new WebhookAdapter(
      { url: 'https://hooks.example.com/notify' },
      transport,
    );
  });

  describe('send', () => {
    it('should send a webhook through the transport', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      const sent = transport.getSentWebhooks();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.url).toBe('https://hooks.example.com/notify');
      expect(sent[0]?.payload.recipient).toBe('user-123');
      expect(sent[0]?.payload.subject).toBe('Test Subject');
      expect(sent[0]?.payload.body).toBe('Test body content.');
    });

    it('should include metadata in the webhook payload', async () => {
      await adapter.send(makePayload({ metadata: { orderId: 'order-1' } }));

      const sent = transport.getSentWebhooks();
      expect(sent[0]?.payload.metadata).toEqual({ orderId: 'order-1' });
    });

    it('should reject invalid webhook URLs', async () => {
      const badAdapter = new WebhookAdapter({ url: 'not-a-url' }, transport);
      const result = await badAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.errorMessage).toContain('Invalid webhook URL');
      expect(transport.getSentWebhooks()).toHaveLength(0);
    });

    it('should reject empty webhook URL', async () => {
      const badAdapter = new WebhookAdapter({ url: '' }, transport);
      const result = await badAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.errorMessage).toContain('Invalid webhook URL');
    });

    it('should handle transport failures gracefully', async () => {
      const failingTransport: WebhookTransport = {
        async post() {
          return { success: false, errorMessage: 'Connection refused' };
        },
      };
      const failAdapter = new WebhookAdapter(
        { url: 'https://hooks.example.com/notify' },
        failingTransport,
      );

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.errorMessage).toBe('Connection refused');
    });

    it('should catch transport exceptions and return SendResult', async () => {
      const throwingTransport: WebhookTransport = {
        async post() {
          throw new Error('Network timeout');
        },
      };
      const throwAdapter = new WebhookAdapter(
        { url: 'https://hooks.example.com/notify' },
        throwingTransport,
      );

      const result = await throwAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.errorMessage).toBe('Network timeout');
    });

    it('should set the channel property to webhook', () => {
      expect(adapter.channel).toBe('webhook');
    });
  });

  describe('getSentWebhooks / clearSentWebhooks', () => {
    it('should return sent webhooks from in-memory transport', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ recipient: 'user-456' }));

      expect(adapter.getSentWebhooks()).toHaveLength(2);
    });

    it('should clear sent webhooks', async () => {
      await adapter.send(makePayload());
      adapter.clearSentWebhooks();

      expect(adapter.getSentWebhooks()).toHaveLength(0);
    });

    it('should return empty array for non-InMemoryWebhookTransport', () => {
      const customAdapter = new WebhookAdapter(
        { url: 'https://hooks.example.com/notify' },
        { async post() { return { success: true }; } },
      );
      expect(customAdapter.getSentWebhooks()).toEqual([]);
    });
  });
});

describe('isValidWebhookUrl', () => {
  it('should accept valid HTTP URLs', () => {
    expect(isValidWebhookUrl('http://example.com/webhook')).toBe(true);
    expect(isValidWebhookUrl('https://hooks.slack.com/services/T00/B00/xxx')).toBe(true);
    expect(isValidWebhookUrl('https://example.com:8080/hook')).toBe(true);
  });

  it('should reject invalid URLs', () => {
    expect(isValidWebhookUrl('')).toBe(false);
    expect(isValidWebhookUrl('not-a-url')).toBe(false);
    expect(isValidWebhookUrl('ftp://example.com/hook')).toBe(false);
    expect(isValidWebhookUrl('://missing-scheme.com')).toBe(false);
  });
});

describe('formatWebhookBody', () => {
  it('should format payload into webhook body with timestamp', () => {
    const payload = makePayload({ metadata: { key: 'value' } });
    const body = formatWebhookBody(payload);

    expect(body.recipient).toBe('user-123');
    expect(body.subject).toBe('Test Subject');
    expect(body.body).toBe('Test body content.');
    expect(body.channel).toBe('webhook');
    expect(body.priority).toBe('normal');
    expect(body.metadata).toEqual({ key: 'value' });
    expect(body.timestamp).toBeDefined();
    expect(() => new Date(body.timestamp)).not.toThrow();
  });

  it('should handle payload without metadata', () => {
    const payload = makePayload();
    const body = formatWebhookBody(payload);

    expect(body.metadata).toBeUndefined();
  });
});

